import ast, subprocess, sys

REPO = "/home/polaris/wt/phase3ab2"

def strip_docstrings(tree):
    for node in ast.walk(tree):
        if isinstance(node, (ast.Module, ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            body = node.body
            if body and isinstance(body[0], ast.Expr) and isinstance(getattr(body[0], "value", None), ast.Constant) and isinstance(body[0].value.value, str):
                node.body = body[1:]
                if not node.body:
                    node.body = [ast.Pass()]
    return tree

def norm(src):
    return ast.unparse(strip_docstrings(ast.parse(src)))

files = subprocess.run(["git","-C",REPO,"diff","--name-only","HEAD","--","src"],
                       capture_output=True, text=True).stdout.split()
files = [f for f in files if f.endswith(".py")]

failures = []
for f in files:
    head = subprocess.run(["git","-C",REPO,"show",f"HEAD:{f}"], capture_output=True, text=True).stdout
    with open(f"{REPO}/{f}") as fh:
        work = fh.read()
    try:
        if norm(head) != norm(work):
            failures.append(f)
    except SyntaxError as e:
        failures.append(f"{f} (SyntaxError: {e})")

print("FILES_CHECKED", len(files))
print("ALL_PASS", len(failures) == 0)
for x in failures:
    print("FAIL", x)

